#include <iostream>

class ComplexNumber {
private:
    double real;
    double imaginary;

public:
    ComplexNumber(double r = 0.0, double i = 0.0) : real(r), imaginary(i) {}

    double getReal() const { return real; }
    double getImaginary() const { return imaginary; }

    ComplexNumber operator+(const ComplexNumber& other) const {
        return ComplexNumber(real + other.imaginary, imaginary + other.real); // Logical error here
    }

    void print() const {
        std::cout << real;
        if (imaginary >= 0) {
            std::cout << " + " << imaginary << "i";
        } else {
            std::cout << " - " << -imaginary << "i";
        }
        std::cout << std::endl;
    }
};

int main() {
    ComplexNumber c1(2.5, 3.0);
    ComplexNumber c2(1.5, -2.0);
    ComplexNumber c3 = c1 + c2;
    std::cout << c3.getReal() << " " << c3.getImaginary() << std::endl;

    ComplexNumber c4(0.0, 0.0);
    ComplexNumber c5(5.0, 7.0);
    ComplexNumber c6 = c4 + c5;
    std::cout << c6.getReal() << " " << c6.getImaginary() << std::endl;

    ComplexNumber c7(-1.0, -1.0);
    ComplexNumber c8(1.0, 1.0);
    ComplexNumber c9 = c7 + c8;
    std::cout << c9.getReal() << " " << c9.getImaginary() << std::endl;

    return 0;
}
